const STORAGE_KEY = "priority-agent.book-notes";

function normalizeTags(input) {
  return String(input || "")
    .split(",")
    .map((tag) => tag.trim().toLowerCase())
    .filter(Boolean);
}

function createStore(storage = window.localStorage) {
  let notes = [];

  function load() {
    // TODO: restore notes from storage, tolerate malformed JSON.
    notes = [];
    return notes;
  }

  function save() {
    // TODO: persist notes to storage.
  }

  function addNote({ title, body, tags }) {
    // TODO: create a note with id, title, body, tags, createdAt.
    return null;
  }

  function deleteNote(id) {
    // TODO: remove a note by id and persist.
    return false;
  }

  function listNotes({ search = "", tag = "" } = {}) {
    // TODO: return newest-first notes filtered by title/body search and tag.
    return notes;
  }

  return { load, save, addNote, deleteNote, listNotes, _all: () => notes };
}

function renderNotes(store, root, filters = {}) {
  const notes = store.listNotes(filters);
  root.innerHTML = "";
  if (notes.length === 0) {
    root.innerHTML = '<p class="empty">No notes yet.</p>';
    return;
  }
  for (const note of notes) {
    const article = document.createElement("article");
    article.className = "note-card";
    article.innerHTML = `
      <h2></h2>
      <p class="note-body"></p>
      <p class="note-tags"></p>
      <button type="button" data-delete="${note.id}">Delete</button>
    `;
    article.querySelector("h2").textContent = note.title;
    article.querySelector(".note-body").textContent = note.body;
    article.querySelector(".note-tags").textContent = note.tags.map((tag) => `#${tag}`).join(" ");
    root.appendChild(article);
  }
}

function init() {
  if (typeof document === "undefined") return;
  const store = createStore(window.localStorage);
  const root = document.getElementById("notes");
  const title = document.getElementById("title");
  const body = document.getElementById("body");
  const tags = document.getElementById("tags");
  const search = document.getElementById("search");
  const tagFilter = document.getElementById("tag-filter");
  store.load();
  const refresh = () => renderNotes(store, root, { search: search.value, tag: tagFilter.value });
  document.getElementById("add-note").addEventListener("click", () => {
    store.addNote({ title: title.value, body: body.value, tags: tags.value });
    title.value = "";
    body.value = "";
    tags.value = "";
    refresh();
  });
  root.addEventListener("click", (event) => {
    const id = event.target && event.target.dataset ? event.target.dataset.delete : "";
    if (id) {
      store.deleteNote(id);
      refresh();
    }
  });
  search.addEventListener("input", refresh);
  tagFilter.addEventListener("input", refresh);
  refresh();
}

if (typeof module !== "undefined") {
  module.exports = { STORAGE_KEY, normalizeTags, createStore };
}
init();
