cat > fixtures/live_frontend/book_notes/test-book-notes.cjs <<'JS'
const assert = require("assert");
const { STORAGE_KEY, normalizeTags, createStore } = require("./app.js");

function fakeStorage(seed = {}) {
  const data = { ...seed };
  return {
    getItem(key) {
      return Object.prototype.hasOwnProperty.call(data, key) ? data[key] : null;
    },
    setItem(key, value) {
      data[key] = String(value);
    },
    removeItem(key) {
      delete data[key];
    },
    _data: data,
  };
}

assert.deepStrictEqual(normalizeTags(" Rust, UI ,, rust "), ["rust", "ui", "rust"]);

const storage = fakeStorage();
const store = createStore(storage);
assert.deepStrictEqual(store.load(), []);

const originalNow = Date.now;
Date.now = () => 1700000000000;
const first = store.addNote({
  title: "Rust ownership",
  body: "Borrowing prevents data races",
  tags: "rust, systems",
});
const second = store.addNote({
  title: "Design notes",
  body: "Keep the interface calm and searchable",
  tags: ["ui", "product"],
});
Date.now = originalNow;

assert.ok(first.id && second.id && first.id !== second.id, "notes need stable unique ids");
assert.deepStrictEqual(first.tags, ["rust", "systems"]);
assert.deepStrictEqual(second.tags, ["ui", "product"]);
assert.strictEqual(store.listNotes().length, 2);
assert.strictEqual(store.listNotes()[0].id, second.id, "newest note should be first even when two notes share the same timestamp");
assert.strictEqual(store.listNotes({ search: "borrow" }).length, 1);
assert.strictEqual(store.listNotes({ search: "DESIGN" })[0].id, second.id);
assert.strictEqual(store.listNotes({ tag: "Rust" })[0].id, first.id);
assert.strictEqual(store.listNotes({ tag: "missing" }).length, 0);

const saved = JSON.parse(storage.getItem(STORAGE_KEY));
assert.strictEqual(saved.length, 2, "notes should persist to localStorage");

const restored = createStore(fakeStorage({ [STORAGE_KEY]: storage.getItem(STORAGE_KEY) }));
assert.strictEqual(restored.load().length, 2, "load should restore persisted notes");

assert.strictEqual(restored.deleteNote(first.id), true);
assert.strictEqual(restored.deleteNote("not-found"), false);
assert.strictEqual(restored.listNotes().length, 1);

const malformed = createStore(fakeStorage({ [STORAGE_KEY]: "{bad json" }));
assert.deepStrictEqual(malformed.load(), [], "malformed storage should not crash");
console.log("book notes behavior ok");
